_CHANGE_WORKSPACE_HTML = """<section data-component="change-workspace" class="main" style="margin-top:18px"><div class="card inventoryCard"><div class="toolbar"><div><div class="eyebrow">Change Workspace</div><h2>Terraform Change Pipeline</h2><p>Draft &rarr; Patch &rarr; Plan Preview &rarr; Approval &rarr; CI/CD Trigger workflow</p></div><div class="filters"><select id="changeStatusFilter"><option value="">All statuses</option><option>Draft</option><option>PatchGenerated</option><option>ValidationPassed</option><option>PlanReady</option><option>PendingApproval</option><option>Approved</option><option>ExecutionReady</option><option>InventoryRefreshed</option></select></div></div><form class="draftForm" id="draftForm"><label class="wide">Change Type<select id="draftChangeType"><option value="terraform_resource_update">Terraform Resource Update</option><option value="terraform_variable_update">Terraform Variable Update</option><option value="terraform_module_update">Terraform Module Update</option></select></label><label class="wide">Object ID<input id="draftObjectId" value="tf/resources/dev/aws_instance/web-server" /></label><label>New Value / Param<input id="draftMaxReplicas" type="text" value="t3.medium" placeholder="e.g. instance_type value" /></label><label>Environment<select id="draftCurrentLevel"><option value="dev">dev</option><option value="sit">sit</option><option value="uat">uat</option><option value="prod">prod</option></select></label><label class="wide">Reason<input id="draftReason" value="resize web-server for load test" /></label><div class="draftActions wide"><button class="btn" type="submit">Create Draft</button><span class="muted">Creates patch preview from inventory data; no source mutation</span></div></form><pre class="draftResult mono" id="patchPreview">Submit Create Draft to preview terraform patch diff.</pre><div class="tableMeta"><span id="changeCount">Loading changes...</span><span>Platform proposes changes &middot; your existing CICD executes them</span></div><div class="tableWrap"><table class="table changeHistoryTable"><thead><tr><th>Change</th><th>Status</th><th>Env</th><th>Artifacts</th><th>Source</th></tr></thead><tbody id="changeRows"><tr><td colspan="5" class="empty">Loading...</td></tr></tbody></table></div></div><aside class="card detailCard actionDetailCard"><div class="detailHead"><div><div class="eyebrow">Change Detail</div><h2 id="changeDetailTitle">No change selected</h2></div><span class="pill" id="changeDetailStatus">idle</span></div><div class="changeSummaryGrid" id="changeSummaryGrid"><div class="changeInfoCard"><span>Status</span><b>No change selected</b><small>Create or select a change</small></div><div class="changeInfoCard"><span>Object</span><b>-</b><small>-</small></div><div class="changeInfoCard"><span>Environment</span><b>-</b><small>-</small></div><div class="changeInfoCard"><span>Artifacts</span><b>0</b><small>none</small></div></div><div class="changePanel" id="changeObjectCard"><span class="changePanelTitle">Object Context</span><div class="empty">Select a change from the table.</div></div><div class="changePanel" id="changeDiffCard"><span class="changePanelTitle">Terraform Patch Diff</span><div class="empty">Patch preview will appear after draft generation.</div></div><div class="changePanel" id="changeArtifactsCard"><span class="changePanelTitle">Artifacts</span><div class="empty">No artifacts yet.</div></div><div class="eyebrow" style="margin-top:10px">Raw JSON</div><pre class="detail mono changeRaw" id="changeDetail">Select a change from the table.</pre><div class="flowPanel"><div class="flowMeta"><div><span>Current status</span><b id="flowCurrentLabel">No change selected</b></div><div><span>Next recommended action</span><b id="flowNextAction">Create Draft</b></div></div><div class="flowRail" id="flowRail"><div class="flowStep" data-step="PatchGenerated" data-index="1"><b>Patch</b><small>tf diff</small></div><div class="flowStep" data-step="ValidationPassed" data-index="2"><b>Validate</b><small>policy</small></div><div class="flowStep" data-step="PlanReady" data-index="3"><b>Plan</b><small>tf plan</small></div><div class="flowStep" data-step="PendingApproval" data-index="4"><b>Approval</b><small>submit</small></div><div class="flowStep" data-step="Approved" data-index="5"><b>Decision</b><small>approved</small></div><div class="flowStep" data-step="ExecutionReady" data-index="6"><b>CI/CD</b><small>create PR</small></div><div class="flowStep" data-step="InventoryRefreshed" data-index="7"><b>Refresh</b><small>snapshot</small></div></div></div><div class="stageGrid"><div class="stageCard" data-statuses="PatchGenerated ValidationPassed"><div class="stageHead"><b>Patch &amp; Validation</b><span class="pill">PatchGenerated &rarr; ValidationPassed</span></div><div class="stageStep">Generate Terraform patch (HCL diff), then run policy validation checks.</div><div class="draftActions"><button class="btn" data-action="validate" onclick="runSelectedAction('validate')">Validate</button></div></div><div class="stageCard" data-statuses="ValidationPassed PlanReady PendingApproval Approved"><div class="stageHead"><b>Plan Preview &amp; Approval</b><span class="pill">PlanReady &rarr; PendingApproval &rarr; Approved</span></div><div class="stageStep">Run terraform plan dry-run preview, submit to approval adapter (GitHub PR / ServiceNow / Jira).</div><div class="draftActions"><button class="btn" data-action="plan" onclick="runSelectedAction('plan')">Run Plan</button><button class="btn" data-action="submit-approval" onclick="runSelectedAction('submit-approval')">Submit Approval</button><button class="btn" data-action="approve" onclick="runSelectedAction('approve')">Approve</button><button class="btn" data-action="reject" onclick="runSelectedAction('reject')">Reject</button></div></div><div class="stageCard" data-statuses="Approved ExecutionReady InventoryRefreshed"><div class="stageHead"><b>CI/CD Trigger &amp; Refresh</b><span class="pill">ExecutionReady &rarr; InventoryRefreshed</span></div><div class="stageStep">Create PR via Repo Adapter; trigger existing CICD pipeline. Platform does not run terraform apply directly.</div><div class="draftActions"><button class="btn" data-action="execute" onclick="runSelectedAction('execute')">Trigger CI/CD (Create PR)</button><button class="btn" data-action="refresh-inventory" onclick="runSelectedAction('refresh-inventory')">Refresh Snapshot</button></div></div></div><div class="stageHint"><b>GitOps mode:</b> Platform proposes changes via PR. Your existing CICD (GitHub Actions / Jenkins / Atlantis) executes terraform apply.</div><pre class="draftResult mono actionLog" id="actionResult">Select a change, then run validation / plan / approval / CI/CD trigger actions.</pre><div class="eyebrow" style="margin-top:14px">Audit Timeline</div><div class="changeTimeline" id="auditTrail"><div class="empty">No audit trail selected</div></div></aside></section>"""

_CHANGE_WORKSPACE_SCRIPT = """function formatArtifactSummary(keys){const list=keys||[];return list.length?`${list.length} artifacts: ${list.slice(0,3).join(', ')}${list.length>3?'...':''}`:'0 artifacts';}
async function loadChanges(){const qs=new URLSearchParams();if(changeStatusFilter.value)qs.set('status',changeStatusFilter.value);const payload=await api('/changes'+(qs.toString()?'?'+qs.toString():''));const items=payload.items||[];changeCount.textContent=`${items.length} tracked changes`;changeRows.innerHTML=items.length?items.map(x=>`<tr onclick="loadChangeDetail('${encodeURIComponent(x.id)}')"><td><div class="cellMain"><b>${esc(x.id)}</b><div class="changeCompactMeta mono" title="${esc(x.object_id)}">${esc(x.object_id)}</div></div></td><td><span class="pill changeStatusBadge">${esc(x.status)}</span></td><td><span class="changeCompactMeta">${esc(x.env||'-')}</span></td><td><span class="changeArtifactBadge" title="${esc((x.artifact_keys||[]).join(', '))}">${esc(formatArtifactSummary(x.artifact_keys))}</span></td><td><div class="mono cellPath changeCompactMeta" title="${esc(x.source_path)}">${esc(x.source_path||'-')}</div></td></tr>`).join(''):'<tr><td colspan="5" class="empty">No changes yet. Create a draft to start.</td></tr>';}
function jsonShort(value){if(value===undefined)return '-';if(value===null)return 'null';if(typeof value==='string')return value;return JSON.stringify(value);}
function renderChangeDetailCards(change){const artifacts=change.artifacts||{};const artifactKeys=Object.keys(artifacts);const scope=change.scope||{};const current=change.current_spec||{};const proposed=change.proposed_spec||{};changeSummaryGrid.innerHTML=`<div class="changeInfoCard"><span>Status</span><b>${esc(change.status)}</b><small>${esc(change.change_type||'change')}</small></div><div class="changeInfoCard"><span>Object</span><b title="${esc(change.object_id)}">${esc(current.serviceName||change.object_id)}</b><small>${esc(change.object_id)}</small></div><div class="changeInfoCard"><span>Environment</span><b>${esc(scope.env||change.env||'-')}</b><small>${esc(scope.namespace||'-')}</small></div><div class="changeInfoCard"><span>Artifacts</span><b>${artifactKeys.length}</b><small>${esc(artifactKeys.join(', ')||'none')}</small></div>`;changeObjectCard.innerHTML=`<span class="changePanelTitle">Object Context</span><div class="changePanelBody"><div class="kvRow"><b>Object ID</b><span class="mono">${esc(change.object_id)}</span></div><div class="kvRow"><b>Source</b><span class="mono">${esc(change.source_path||'-')}</span></div><div class="kvRow"><b>Namespace</b><span>${esc(scope.target_namespace||scope.namespace||'-')}</span></div><div class="kvRow"><b>Target Cluster</b><span>${esc(scope.cluster_name||'-')}</span></div><div class="kvRow"><b>Workflow</b><span class="mono">${esc(scope.workflow_id||'-')}</span></div><div class="kvRow"><b>Reason</b><span>${esc(change.reason||'-')}</span></div></div>`;const fieldDiff=(artifacts.field_diff||Object.keys(proposed).map(field=>({field,from:current[field],to:proposed[field]})));changeDiffCard.innerHTML=`<span class="changePanelTitle">Spec Diff</span><div class="changePanelBody">${fieldDiff.length?fieldDiff.map(x=>`<div class="diffRow"><div><span>Field</span><code>${esc(x.field)}</code></div><div><span>From</span><code>${esc(jsonShort(x.from))}</code></div><div><span>To</span><code>${esc(jsonShort(x.to))}</code></div></div>`).join(''):'<div class="empty">No field diff</div>'}</div>`;changeArtifactsCard.innerHTML=`<span class="changePanelTitle">Artifacts</span><div class="artifactList">${artifactKeys.length?artifactKeys.map(k=>`<span class="chip">${esc(k)}</span>`).join(''):'<div class="empty">No artifacts yet.</div>'}</div>`;}
function renderAuditTimeline(items){auditTrail.innerHTML=items&&items.length?items.map(x=>`<div class="timelineItem"><div class="timelineDot">${esc(x.sequence)}</div><div><b>${esc(x.type)}</b><small><span class="mono">${esc(x.actor||'system')}</span></small></div></div>`).join(''):'<div class="empty">No audit events</div>';}
async function loadChangeDetail(id){window.selectedChangeId=id;const d=await api('/changes/'+encodeURIComponent(id));const a=await api('/changes/'+encodeURIComponent(id)+'/audit');window.selectedChangeStatus=d.status;window.selectedChangeDetail=d;changeDetail.textContent=JSON.stringify(d,null,2);changeDetailTitle.textContent=d.id;changeDetailStatus.textContent=d.status;renderChangeDetailCards(d);updateActionControls(d.status);renderAuditTimeline((a.items||[]).sort((a,b)=>(a.sequence||0)-(b.sequence||0)));}
function buildDraftPreviewPayload(){var val=document.getElementById('draftMaxReplicas')?document.getElementById('draftMaxReplicas').value:'';var env=document.getElementById('draftCurrentLevel')?document.getElementById('draftCurrentLevel').value:'dev';if(draftChangeType.value==='terraform_variable_update'){return {object_id:draftObjectId.value,change_type:'terraform_variable_update',reason:draftReason.value,proposed:{value:val,env:env}};}if(draftChangeType.value==='terraform_module_update'){return {object_id:draftObjectId.value,change_type:'terraform_module_update',reason:draftReason.value,proposed:{version:val,env:env}};}return {object_id:draftObjectId.value,change_type:'terraform_resource_update',reason:draftReason.value,proposed:{param_value:val,env:env}};}
async function createDraftPreview(evt){evt.preventDefault();patchPreview.textContent='Creating draft preview...';const payload=buildDraftPreviewPayload();const res=await api('/changes/draft-preview',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});if(res.detail){patchPreview.textContent=JSON.stringify(res,null,2);return;}patchPreview.textContent=(res.patch_preview||{}).yaml_diff||JSON.stringify(res,null,2);await loadChanges();await loadChangeDetail(res.change.id);}
const allowedActionsByStatus={Draft:[],PatchGenerated:['validate'],ValidationPassed:['validate','plan'],PlanReady:['submit-approval'],PendingApproval:['approve','reject'],Approved:['execute'],ExecutionReady:['refresh-inventory'],InventoryRefreshed:[]};
const changeFlowSteps=[{status:'Draft',label:'Draft',hint:'created',next:'Create Draft'},{status:'PatchGenerated',label:'Patch',hint:'yaml diff',next:'Validate'},{status:'ValidationPassed',label:'Validate',hint:'policy ok',next:'Run Plan'},{status:'PlanReady',label:'Plan',hint:'dry-run ok',next:'Submit'},{status:'PendingApproval',label:'Approval',hint:'waiting',next:'Approve'},{status:'Approved',label:'Decision',hint:'approved',next:'Execute'},{status:'ExecutionReady',label:'Execute',hint:'PR created',next:'Refresh'},{status:'InventoryRefreshed',label:'Refresh',hint:'done',next:'Done'}];
function renderFlowRail(status){const idx=changeFlowSteps.findIndex(s=>s.status===status);flowCurrentLabel.textContent=status||'No change selected';flowNextAction.textContent=idx>=0&&idx<changeFlowSteps.length-1?changeFlowSteps[idx].next:'Done';flowRail.innerHTML=changeFlowSteps.map((s,i)=>`<div class="flowStep ${i<idx?'done':i===idx?'current':'todo'}" data-step="${s.status}" data-index="${i+1}"><b>${s.label}</b><small>${s.hint}</small></div>`).join('');}
function updateActionControls(status){const allowed=new Set(allowedActionsByStatus[status]||[]);renderFlowRail(status);document.querySelectorAll('.stageCard').forEach(card=>{const statuses=(card.dataset.statuses||'').split(' ');card.className=statuses.includes(status)?'stageCard active':'stageCard';});document.querySelectorAll('[data-action]').forEach(button=>{button.disabled=!allowed.has(button.dataset.action);});}
async function runSelectedAction(action){if(!window.selectedChangeId){actionResult.textContent='Select a change first.';return;}const allowed=new Set(allowedActionsByStatus[window.selectedChangeStatus]||[]);if(!allowed.has(action)){actionResult.textContent='Action '+action+' not allowed for status '+window.selectedChangeStatus;return;}let endpoint=action;let payload={};if(action==='submit-approval'){endpoint='submit';payload={requester:'sre-user',note:'ready for review'};}if(action==='approve'){endpoint='approve';payload={approver:'manager',decision:'approve',comment:'approved'};}if(action==='reject'){endpoint='approve';payload={approver:'manager',decision:'reject',comment:'needs revision'};}if(action==='execute'){payload={executor:'sre-bot'};const scope=((window.selectedChangeDetail||{}).scope||{});actionResult.textContent='Execution preflight\\ncluster='+((scope.cluster_name)||'-')+'\\nnamespace='+((scope.target_namespace||scope.namespace)||'-')+'\\nworkflow='+(scope.workflow_id||'-')+'\\n';}if(action==='refresh-inventory')payload={actor:'sre-bot',mode:'local_snapshot'};if(action!=='execute')actionResult.textContent='Running '+action+'...';const res=await api('/changes/'+encodeURIComponent(window.selectedChangeId)+'/'+endpoint,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});actionResult.textContent=(action==='execute'?actionResult.textContent+'\\n':'')+JSON.stringify(res,null,2);await loadChanges();await loadChangeDetail(window.selectedChangeId);}
function bindChangeWorkspaceEvents(){changeStatusFilter.addEventListener('change',loadChanges);draftChangeType.addEventListener('change',function(){if(draftChangeType.value==='terraform_variable_update'&&draftObjectId.value.startsWith('tf/resources/')){draftObjectId.value='tf/variables/dev/vpc_cidr';draftReason.value='update dev VPC CIDR block';}if(draftChangeType.value==='terraform_module_update'&&draftObjectId.value.startsWith('tf/resources/')){draftObjectId.value='tf/modules/dev/vpc_baseline';draftReason.value='upgrade vpc_baseline module to v2.1.0';}if(draftChangeType.value==='terraform_resource_update'){draftObjectId.value='tf/resources/dev/aws_instance/web-server';draftReason.value='resize web-server for load test';}});draftForm.addEventListener('submit',createDraftPreview);}
"""


def render_change_workspace_html():
    return _CHANGE_WORKSPACE_HTML


def change_workspace_script():
    return _CHANGE_WORKSPACE_SCRIPT
